<template><section class="page"><van-nav-bar title="汇率" left-arrow @click-left="router.back()"/><div v-if="loading" class="state-card"><van-loading/></div><van-empty v-else-if="error" image="error" :description="error"><van-button @click="load">重试</van-button></van-empty><van-empty v-else-if="!rates.length" description="账本中暂无汇率"/><van-cell-group v-else inset><van-cell v-for="rate in rates" :key="`${rate.currency}-${rate.effective_date}`" :title="rate.currency_pair" :value="rate.rate" :label="rate.effective_date"/></van-cell-group><van-notice-bar style="margin-top:16px">汇率以 Beancount 账本为真值；本页不建立第二份数据。</van-notice-bar></section></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{useRouter}from'vue-router';import{exchangeRatesApi,type ExchangeRate}from'../../api/exchangeRates';import type{ApiError}from'../../api/client';const router=useRouter(),rates=ref<ExchangeRate[]>([]),loading=ref(false),error=ref('');async function load(){loading.value=true;error.value='';try{rates.value=await exchangeRatesApi.getExchangeRates()}catch(reason){error.value=(reason as ApiError).message}finally{loading.value=false}}onMounted(load)</script>
